import{_ as p,o as i,c as e,j as r,a,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const v=JSON.parse('{"title":"Oblivionis-遗忘女神","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/2.社交类/Oblivionis-遗忘女神.md","filePath":"4.资源分区/1.血统与训练/2.社交类/Oblivionis-遗忘女神.md"}'),t={name:"4.资源分区/1.血统与训练/2.社交类/Oblivionis-遗忘女神.md"};function s(n,b,l,d,_,c){return i(),e("div",null,[...b[0]||(b[0]=[r("h1",{id:"oblivionis-遗忘女神",tabindex:"-1"},[a("Oblivionis-遗忘女神 "),r("a",{class:"header-anchor",href:"#oblivionis-遗忘女神","aria-label":'Permalink to "Oblivionis-遗忘女神"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),o('<h1 id="oblivionis-遗忘女神-1" tabindex="-1">Oblivionis-遗忘女神 <a class="header-anchor" href="#oblivionis-遗忘女神-1" aria-label="Permalink to &quot;Oblivionis-遗忘女神&quot;">​</a></h1><p>Oblivionis-遗忘女神<br> 血统<br> 特别的，本血统必须轮回者的性别为女性，外貌至少为5，且具有【孤儿】身份专长或者背景上是孤儿才能购买</p><p>D级：D+600<br> 【蓝发魅魔】：<br> 你天生具有高贵的气质和靓丽的外貌，散发着对所有人（尤其是同性）的吸引力，所有女性角色对你的好感度提高一级，不可超过友善</p><p>【蓝色哈基米】：<br> 但在你光鲜的外表下隐藏着恶劣的性格，你获得一种特殊的能量池【哈基力】，这种能量的关键属性为你有事没事就要对别人哈气的【决心】和面对危险时控制自己软糯的【操纵】<br> 【哈基力】的恢复方式： <br> 1、每次长休息后，【哈基力】会恢复至满值。 <br> 2、每进行一次短休息，进行一次【哈基力】关键属性检定，恢复成功数点【哈基力】。</p><p>你学会了一种特殊的攻击方式——【哈气】，你针对15m范围内的一个目标恶语相向，以【风度+社交+专业：哈气+辅助专业：心理学（学识）】进行检定并造成精神伤害。<br> 使用此方法攻击时，你必须数落对方的缺点（哪怕没有也要硬找），比如“你才是最需要练习的那个！”、“为什么不站在我这边！”、“你这个人满脑子只想着自己呢！”<br> 如果实在想不到该说什么，也可以喊出通用的：“哈！”</p><p>虽然很多人都觉得你的行为不知所谓，但也有一些人觉得哈气的你很可爱，你的【哈气】攻击附带1点【魅惑】不良点数，意志豁免。</p><p>【受难的陀螺】<br> 不知为何，你的命运非常凄苦，干什么都不顺利，一件件不幸的事把你当成陀螺一样抽打，你的机运骰获得1点减值。</p><p>C级：C+1200<br> 前置条件：【孤儿】身份专长3级或额外支付12xp<br> 【落魄贵族】<br> 你不是简单的孤儿，事实上，你是某个手眼通天的财阀的大小姐，但是因为一些原因，你暂时无法回归家族，只能暂时在外流浪。<br> 取代【孤儿】身份专长中的C级背景身份效果，改为以上的背景身份，并附带资金、当地的住所、出行工具等。这仍是一个C级命运来源的【背景身份】效果</p><p>【勤俭持家】：<br> 你平时只用少许面包就能支撑起高强度的劳作，具体而言，你【无需饮食】也【无需休息】</p><p>【Work~Work~Work~Work~】：<br> 为了补贴家用，你在许多地方都打过工，这导致你积攒了各种各样的技能。每场影片你可以从以下选项中选择一项你要进行的打工，影片结束后你将获得对应效果：<br> 1.调查兵团替补：【运动】技能提升1级，不超过内在上限。<br> 2.东京巨蛋地下竞技场清洁工：【武技】技能提升1级，不超过内在上限。<br> 3.超级地球应召地狱潜兵：【射击】技能提升1级，不超过内在上限。<br> 4.卡塔昌雇佣兵：【生存】技能提升1级，不超过内在上限。<br> 5.咒术中专门口保安：【学识】技能提升1级，不超过内在上限。<br> 6.秋名山送货员：【器用】技能提升1级，不超过内在上限。<br> 7.摇花手团队群演：【手艺】技能提升1级，不超过内在上限。<br> 8.干瞪眼比赛参赛选手：【专注】技能提升1级，不超过内在上限。<br> 9.刺客兄弟会临时成员：【隐秘】技能提升1级，不超过内在上限。<br> 10.基金会D级人员：【洞察】技能提升1级，不超过内在上限。<br> 11.星野爱的替身演员：【表达】技能提升1级，不超过内在上限。<br> 12.客服：【社交】技能提升1级，不超过内在上限。</p><p>以上每种打工只能选择一次，并且当你完成了所有打工后，你将获得【有钱人】特性<br> 【有钱人】：因为你很有钱，导致别人虽然对你的哈气不爽，但还是会听从你的指挥。被你以【哈气】攻击方式命中的目标，需要以意志豁免对抗出目，若你胜出，则你可以命令对方做出任何不违反他基本价值观的事情，这是一个C级影响心灵来源【思维控制】效果，持续一个场景。</p><p>B级：B+2400<br> 【提抖放哈】<br> 因为打工导致的时间紧张，你经常会退出你所在的团队，但在你离开之前会习惯性地对前队友哈气。<br> 现在你的【哈气】攻击可以同时攻击15m范围内的4个目标，并且当你【哈气】命中后，你可以准备一个反射动作。<br> 直到你的下个回合结束，当其他人尝试攻击你时，你都可以使用这个反射动作调用下回合的标准动作进行一次打断性的移动。<br> 若这次攻击方为你【哈气】命中的目标，这次移动还会使对方受到等同于你那次【哈气】出目的【恶心】不良点数，意志豁免。</p><p>【中二世界观小剧场】<br> 虽然是你主动退出团队的，但是当你看到你的前队友过得好了你还是会破防，于是你准备组建一个更好更酷的蒙面团队<br> 你开启【颂乐人偶】技能树，获得特殊装备【难绷的假面】，该装备视作和此血统同级的奇物，占据面具位。<br> 你可以复制此装备并将其分享给至多4个女性同伴，她们必须身处你的触及范围内、围绕你行动才能享受该效果</p><p>【难绷的假面】<br> 这是一张黑色的蕾丝假面，不知道为什么戴上之后别人就认不出你了。你获得C级命运来源的【伪装】效果，戴上面具后可以任意改变自己的外表。<br> 但是由于面具的结构设计，你的鼻子会被凸显得很大，这导致敌人针对你的鼻梁部位进行攻击时不会获得减值。</p><p>【龙王归来】<br> 经过长时间的自我博弈，在许多次折磨了自己的同伴后，你想通了，你原谅了自己，决定回家继承亿万家产<br> 代替原本的C级【背景身份】，现在你的背景身份变为老牌财团的合法继承人，货真价实的贵族大小姐。具体而言可以轻松捧红或打压一些偶像和乐队团体，并在必要时支付违约金。这个背景身份附带记忆、资产和人际关系，这是一个B级命运来源的【背景身份】效果<br> 此外，你获得【迈巴赫】特性</p><p>【迈巴赫】<br> 作为财阀大小姐的象征，你获得了一种独特的代步工具——【迈巴赫】<br> 在非战斗情况下，你可以打一个电话呼叫司机。经过十分钟的移动时间，家族的司机会把迈巴赫开到你的面前，那之后你可以坐上车以500km/h的时速进行移动，可在一小时至一日内从大陆的一端至另一端。移动过程中，车载音响会无法控制地播放《你若三冬》作为bgm。<br> 由于你不爱和队友交流和分享，所以你的同伴无法乘上你的迈巴赫一起移动，如果他们尝试会被车上的司机轰下来。<br> 这是一个C级命运来源的【旅行】效果</p><p>A级：A+4800<br> 【神人】<br> “你以为我是谁，我可是AveMujica的遗忘女神！”<br> 在度过了许多你招惹来的困难后，你觉得这一切都是世界的错，所以要创造一个让自己舒服的世界，而你就是这个世界的神。<br> 现在，你可以用【哈基力】代替【创世之力】发挥各种用法（不必具有【创世之力】能量池）：</p><p>①每轮一次，你可以用一个迅捷动作消耗1点【哈基力】来修复周围的路面和建筑，视作你直到本轮结束时，获得【免疫B级环境影响】效果</p><p>②每场景一次，你在使用社交技能进行检定时，可以用一个反射动作消耗2点【哈基力】，并说出“相信我吧，因为相信是不需要理由的”<br> 这使你可以重新检定一次，并选取更好的结果</p><p>③每场影片一次，当你死亡时，消耗1点【哈基力】，使你获得B级复活效果<br> 复活过程中你处于灵体状态，除了观察和移动外无法行动，拥有等同于你意志值的结构值，被破坏时复活失败<br> 你需要几个月的时间来复活，但每有一位你的信徒诚心为你哭丧，你的复活时间就缩短一天，最多缩短至一个月</p><p>此外，你的【哈基力】能量池获得类同与【创世之力】的恢复方法<br> 每次短休息，你可以通过一次社交检定来说服周围的目标，告诉他们你是神，相信你就能心想事成。你的【哈基力】回复等同于检定成功数的值。<br> st选开：当你以此方法成功说服一个目标时，你可以选择放弃回复而是使你的【哈基力】能量池提升1点上限。每个可被说服的目标最多提升你的【哈基力】能量池上限一次<br> 你每日恢复的能量仍然不得超过能量池大小的三倍</p><p>你离真正的神很远，但你离正常的人已经不近了。</p><p>【忘记一切】<br> “当太阳升起的时候，就忘掉昨天”<br> 你非常擅长忘掉自己的错误来原谅自己，而熟悉你的人也非常希望忘掉因你而遭遇的各种破事<br> 虽然实现方式不好评价，但这种谁都渴望忘却的场景与你的【哈基力】获得了共鸣</p><p>被你以【哈气】攻击方式命中的目标需要以意志豁免对抗你的出目，若你胜出，则对方会在24小时后遗忘你的一切信息，这是一个B级信息来源的【思维控制】效果<br> 而当其他人与受到此效果的单位接触时，也需要进行一次目标值相同的意志豁免。<br> 若对方未通过，则他也会在24小时后忘记你的一切信息，以这种方式传播的效果范围至多不超过一座城市，这是一个B级信息来源的【模因】效果</p><p>此外，你也可以用这种方式让你自己忘记受到的心灵影响，这使你免疫A级影响心灵来源的效果</p><p>【岁月史书】<br> 成神之后你决定维护自己的威名，把过去犯下的错误全部掩藏掉，不对，“我过去没有犯任何错误，我永远是对的”，应该这么想才对。<br> 现在你的【哈气】攻击每轮一次可以重新掷骰并选取更高的结果，并且你可以通过抢占话语权来体现自己的正确性。</p><p>每轮一次，当你的【哈气】攻击范围内存在单位时，你可以用一个标准动作对他们所有人施展【哈气】，此次攻击不会造成伤害<br> 被命中单位需要以意志豁免对抗你的出目，若你胜出，根据你对他们的指责，他们获得以下对应的效果，持续一个场景</p><p>①若目标为友方单位，你可以喊出类似“你明明就在旁边，你为什么不帮我！”的话语<br> 被命中单位的格挡防御动作获得【强拦截】特性，并且可以对触及范围内的友方单位提供【全遮蔽】</p><p>②若目标为敌方单位，你可以喊出类似“都是你的错！如果不是你先伤害我，我怎么会伤害你！”的话语<br> 被命中单位会因为你的指责而产生自我怀疑，这使对方先攻降低18点（至多降为1），并且你的【哈气】攻击额外具有3L武器伤害。</p><p>下属技艺</p><p>【悲伤骑士的亲属关系】<br> 前置：A级血统<br> B+2000</p><p>【绝望的侄女】<br> 购买此技艺后，你在【忘记一切】中的【思维控制】效果还会使目标认为你是他的侄女<br> 这会使得目标对你的好感度提升4级（不超过友善），足以从仇视提升至冷漠，不会因此提高至极端好感<br> 值得注意的是，好感度提升并不代表对方会无条件对你好，也不意味着会让死敌放过你</p><p>【千里追小姨】<br> 此外，当同场景内存在认为你是自己的侄女的单位时，你每回合能额外向该单位进行一次移动。</p><p>【死亡骑士的多重人格】<br> B+2000</p><p>【我才是你唯一的朋友】<br> 你现在获得了一个和你有着巨大差异的第二人格，你可以自由为其命名<br> 当你需要时，可以使用一个整轮动作将你切换为该人格（该技艺不附赠换装，请自行解决）<br> 在该人格状态下，你额外获得11点技能点，由你自由分配至你的技能上（购买时选定并分配，无法改变）<br> 由此方法获得的技能点无法使你的技能超过上限</p><p>【全都不会弹！】<br> 当你切换为第二人格时，你无法使用任何技艺或进行攻击，仅能进行技能对应的基础行动检定（如攀爬、跳跃等）</p><p>【模仿学习】<br> 每场影片过后，若你在该影片中至少战胜了一位同级的敌人，则第二人格提供的技能点增长2点</p><p>【恐惧骑士的信用问题】<br> B+2000</p><p>【我只是个雇佣兵】<br> 现在当你使用【提抖放哈】中的反射动作移动时，可以额外喊出“你是觉得我不值得信任吗？！”并使你此次的移动距离翻倍</p><p>【乐队圈传来噩耗】<br> 为了维持身材和外貌，你经常服用一些充满科技与狠活的食品<br> 每场影片过后，你获得1点【美颜】和1点【瘦身】</p><p>【美颜】不会使你的外貌提升，但每点【美颜】会抵消使你【外貌】下降的1点效果<br> 【瘦身】不会使你的体积下降，但每点【瘦身】会抵消1点使你虚拟体积增加的效果，抵消后闪避防御提升等效果仍然存在<br> 此外，每点【瘦身】会使你获得1点闪避防御提升，【隐匿】技能获得1点内在加值，并且【哈气】攻击上获得1点【高速】</p><p>【爱欲骑士的热度观念】<br> B+2000</p><p>【蹭热度】<br> 当你的触及范围内存在友方单位时，该单位每有30点声望就使你获得5点临时的同类声望（善名/恶名），每个单位至多使你获得50点声望</p><p>【黑红也是红】<br> 每场影片结束时，你在影片中每获得1点【恶名】声望，都使你额外获得1点【善名】声望，至多获得35点</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',46)])])}const m=p(t,[["render",s]]);export{v as __pageData,m as default};
